prompt --application/shared_components/plugins/dynamic_action/com_enhanceigwithtreegrid_plugin
begin
wwv_flow_imp_shared.create_plugin(
 p_id=>wwv_flow_imp.id(8258602084120096078)
,p_plugin_type=>'DYNAMIC ACTION'
,p_name=>'COM.ENHANCEIGWITHTREEGRID.PLUGIN'
,p_display_name=>'Enhance Interactive Grid with Treegrid'
,p_category=>'EXECUTE'
,p_image_prefix => nvl(wwv_flow_application_install.get_static_plugin_file_prefix('DYNAMIC ACTION','COM.ENHANCEIGWITHTREEGRID.PLUGIN'),'')
,p_javascript_file_urls=>wwv_flow_string.join(wwv_flow_t_varchar2(
'#PLUGIN_FILES#js/jquery.treegrid.js',
'#PLUGIN_FILES#js/script.js'))
,p_css_file_urls=>'#PLUGIN_FILES#css/jquery.treegrid.css'
,p_plsql_code=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- =============================================================================',
'--',
'--  Created by Richard Baldogi',
'--',
'--  This plug-in helps to append a treegrid component to a designated Interactive Grid.',
'--',
'--  License: MIT',
'--',
'--  GitHub: https://github.com/baldogiRichard/apex-treegrid-enhancement-for-ig',
'--',
'-- =============================================================================',
'',
'--render function',
'function render ',
'  ( p_dynamic_action in apex_plugin.t_dynamic_action',
'  , p_plugin         in apex_plugin.t_plugin ',
'  )',
'return apex_plugin.t_dynamic_action_render_result',
'as',
'    l_result          apex_plugin.t_dynamic_action_render_result;',
'    l_ajax_id         varchar2(4000) := apex_plugin.get_ajax_identifier;',
'',
'    --Initialization Javascript Code',
'    l_init_js                          varchar2(32767)                          := nvl(apex_plugin_util.replace_substitutions(p_dynamic_action.init_javascript_code), ''undefined'');   ',
'',
'    --Attributes',
'    l_table_selector                   p_dynamic_action.attribute_01%type       := p_dynamic_action.attribute_01;',
'    l_row_selector                     p_dynamic_action.attribute_02%type       := p_dynamic_action.attribute_02;',
'    l_id_column                        p_dynamic_action.attribute_03%type       := upper(p_dynamic_action.attribute_03);',
'    l_parent_id_column                 p_dynamic_action.attribute_04%type       := upper(p_dynamic_action.attribute_04);',
'    l_expand_collapse                  p_dynamic_action.attribute_05%type       := p_dynamic_action.attribute_05;',
'    l_display_column                   p_dynamic_action.attribute_06%type       := upper(p_dynamic_action.attribute_06);',
'    l_depth_level_column               p_dynamic_action.attribute_07%type       := upper(p_dynamic_action.attribute_07);',
'',
'    --Affected region',
'    l_affected_region_id               p_dynamic_action.affected_region_id%type := p_dynamic_action.affected_region_id;',
'    l_region_rec                       apex_application_page_regions%rowtype;',
'    l_region_id                        varchar2(100);',
'',
'begin',
'',
'    --debug',
'    if apex_application.g_debug',
'    then',
'        apex_plugin_util.debug_dynamic_action',
'          ( p_plugin         => p_plugin',
'          , p_dynamic_action => p_dynamic_action',
'          );',
'    end if;',
'',
'    --get region infos about IG',
'    select aapr.* ',
'    into l_region_rec',
'    from apex_application_page_regions aapr',
'    where region_id = l_affected_region_id;',
'',
'    l_region_id := case when l_region_rec.static_id is null',
'                          then ''R'' || to_char(l_region_rec.region_id)',
'                        else to_char(l_region_rec.static_id)',
'                   end;',
'',
'    --Pass attribute values to JSON',
'    apex_json.initialize_clob_output;',
'',
'        apex_json.open_object;',
'',
'            apex_json.write(''tableSelector''     , l_table_selector                  );',
'            apex_json.write(''rowSelector''       , l_row_selector                    );',
'            apex_json.write(''idColumn''          , l_id_column                       );',
'            apex_json.write(''parentIdColumn''    , l_parent_id_column                );',
'            apex_json.write(''initialState''      , l_expand_collapse                 );',
'            apex_json.write(''treeColumn''        , l_display_column                  );',
'            apex_json.write(''depthLevel''        , l_depth_level_column              );',
'            apex_json.write(''regionID''          , l_region_id                       );',
'            apex_json.write(''reportType''        , l_region_rec.source_type_code     );  ',
'            ',
'        apex_json.close_object;',
'',
'        l_result.javascript_function := ''function(){ENHANCEIGWITHTREEGRID.main('' || apex_json.get_clob_output || '','' || l_init_js || '');}'';',
'    ',
'    apex_json.free_output;',
'    ',
'    return l_result;',
'',
'exception when no_data_found then',
'',
'    apex_error.add_error ( p_message          => ''Please provide the designated Interactive Grid in the Affected Elements attribute!''',
'                         , p_display_location => apex_error.c_on_error_page );',
'    ',
'end render;'))
,p_api_version=>1
,p_render_function=>'render'
,p_standard_attributes=>'REGION'
,p_substitute_attributes=>true
,p_version_scn=>15539477131413
,p_subscribe_plugin_settings=>true
,p_help_text=>'Just making a happy little Plug-in to beat the devil out of the IG.'
,p_version_identifier=>'1.0'
,p_about_url=>'https://github.com/baldogiRichard/apex-treegrid-enhancement-for-ig'
,p_files_version=>945
);
