 p_id=>wwv_flow_imp.id(1541004411003698971)
,p_plug_name=>'Demo Purposes Only Login'
,p_region_name=>'userTree'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>4501440665235496320
,p_plug_display_sequence=>30
,p_plug_grid_column_span=>4
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select case when connect_by_isleaf = 1 then 0',
'            when level = 1             then 1',
'            else                           -1',
'       end          as status, ',
'       level, ',
'       e.ename      as title, ',
'       ''fa ''||case when d.deptno = 40 ',
'                   then ''fa-user-headset'' ',
'                   else ''fa-user''',
'              end   as icon, ',
'       e.empno      as value, ',
'       null         as tooltip, ',
'       null         as link ',
'from eba_demo_appr_emp e',
'left outer join eba_demo_appr_dept d',
'             on d.deptno = e.deptno ',
'start with mgr is null',
'connect by prior empno = mgr',
'order siblings by ename'))
,p_lazy_loading=>false
