'    apex.navigation',
'      .dialog(pData, {',
'        title:  "Edit Employee",',
'        height: 600,',
'        width:  800,',
'        modal:  true,',
'        close: function() {',
'    // this function fires as soon as the user clicks any Close/Save/Delete that closes the dialog',
