,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_region_id=>wwv_flow_imp.id(42255613585551661)
,p_process_type=>'NATIVE_IG_DML'
,p_process_name=>'OEHR Employees Custom Interactive Grid - Save Interactive Grid Data_1'
,p_attribute_01=>'PLSQL_CODE'
,p_attribute_04=>wwv_flow_string.join(wwv_flow_t_varchar2(
'begin',
'  case :APEX$ROW_STATUS',
'    when ''C'' then',
'      insert into oehr_employees (',
'        first_name,',
'        last_name,',
'        email,',
'        phone_number,',
'        hire_date,',
'        job_id,',
'        salary,',
'        commission_pct',
'       ',
'      )',
'      values (',
'        :FIRST_NAME,',
'        :LAST_NAME,',
'        :EMAIL,',
'        :PHONE_NUMBER,',
'        :HIRE_DATE,',
'        :JOB_ID,',
'        :SALARY,',
'        :COMMISSION_PCT',
'      );',
'',
'    when ''U'' then',
'      update oehr_employees',
'         set first_name      = :FIRST_NAME,',
'             last_name       = :LAST_NAME,',
'             email           = :EMAIL,',
'             phone_number    = :PHONE_NUMBER,',
'             hire_date       = :HIRE_DATE,',
'             job_id          = :JOB_ID,',
'             salary          = :SALARY,',
'             commission_pct  = :COMMISSION_PCT ',
'       where EMPLOYEE_ID = :EMPLOYEE_ID;',
'',
'    when ''D'' then',
'      delete from oehr_employees',
'       where EMPLOYEE_ID = :EMPLOYEE_ID;',
'  end case;',
'end;',
''))
,p_attribute_05=>'Y'
,p_attribute_06=>'Y'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>41773788988015920
);
