'Declare',
'    l_sql clob;',
'    l_report_num number;',
'Begin',
'    Case when :P24_REPORT_TYPE is null then',
'        l_report_num := 1;',
'    else',
'        l_report_num := TO_NUMBER(:P24_REPORT_TYPE);',
'    end case;',
'    l_sql := get_product_report_sql(l_report_num);',
'    return l_sql;',
'    EXCEPTION',
'  WHEN OTHERS THEN',
'    BEGIN',
'      SELECT ''SELECT 1 FROM DUAL'' INTO l_sql FROM DUAL;',
'    EXCEPTION',
'      WHEN OTHERS THEN',
'        l_sql := ''SELECT 1 FROM DUAL'';',
'    END;',
'    RETURN l_sql;',
'end;',
'',
'',
'',
''))
